let _tickingOp=false,_lsOpSimTurn=-1;
function _runOpBoard(raw){if(!_opS||!S.mp||_opS.over)return;const op=S.mp.opRole;const pending=[];while(true){const next=_lsOpSimTurn+1;const td=_lsTurns[next];if(!td||td[op]===undefined)break;pending.push(...(_lsArrify(td[op])||[]));_lsOpSimTurn=next;}const svS=S,svC=CLIFF_SET,svT=TREE_DECO,svR=_rng;S=_opS;CLIFF_SET=_opCliff;TREE_DECO=_opTree;_rng=_opRng;_tickingOp=true;for(const inp of pending)applyInput(inp);const steps=Math.max(1,Math.ceil(SPEED_MUL));const sub=(raw*SPEED_MUL)/steps;for(let i=0;i<steps;i++)tick(sub);_tickingOp=false;_opS=S;_opCliff=CLIFF_SET;_opTree=TREE_DECO;_opRng=_rng;S=svS;CLIFF_SET=svC;TREE_DECO=svT;_rng=svR;}
function applyInput(inp){switch(inp.type){case 'place':{const type=inp.towerType;if(!type||!BASE[type])break;const c=inp.c,r=inp.r;if(!canPlace(type,c,r))break;const cost=effCost(BASE[type].cost);if(S.gold<cost)break;S.gold-=cost;if(type==='lumber'){TREE_DECO=TREE_DECO.filter(t=>!(t.c===c&&t.r===r));break;}S.towers.push({id:rng(),c,r,x:c*CELL+CELL/2,y:r*CELL+CELL/2,type,lv:1,kills:0,cd:0,sf:0,sf2:undefined});break;}case 'wall':{const c=inp.c,r=inp.r;if(S.walls.some(w=>w.c===c&&w.r===r)||S.towers.some(t=>t.c===c&&t.r===r))break;if(S.gold<20)break;S.gold-=20;S.walls.push({id:rng(),c,r,type:'wall',lv:1,hp:300,maxHp:300,hf:0,buildT:5,buildMax:5});break;}case 'stone':{const key=`${inp.c},${inp.r}`;if(S.gold<100)break;S.gold-=100;if(inp.remove)CLIFF_SET.delete(key);else CLIFF_SET.add(key);break;}case 'lumber':{const c=inp.c,r=inp.r;if(!canPlace('lumber',c,r))break;const cost=effCost(BASE.lumber.cost);if(S.gold<cost)break;S.gold-=cost;TREE_DECO=TREE_DECO.filter(t=>!(t.c===c&&t.r===r));break;}case 'usertank':{const c=inp.c,r=inp.r;if(S.gold<350)break;S.gold-=350;const st1=STATS.usertank[0];S.userTanks.push({id:rng(),userTank:true,type:'usertank',c,r,x:c*CELL+CELL/2,y:r*CELL+CELL/2,bodyFacing:0,turretFacing:0,spd:120,cd:0,lv:1,range:st1.range*CELL,dmg:st1.dmg,rate:st1.rate,splashR:st1.splashR*CELL,ammo:'explosive',kills:0});break;}case 'upgrade':{const t=S.towers.find(x=>x.c===inp.c&&x.r===inp.r)||S.userTanks.find(x=>x.c===inp.c&&x.r===inp.r);if(!t)break;if(t.userTank){const lv=t.lv||1;if(lv>=maxLv('usertank'))break;const cost=effCost(upCost('usertank',lv));if(S.gold<cost)break;S.gold-=cost;t.lv=lv+1;const st=STATS.usertank[t.lv-1];t.dmg=st.dmg;t.rate=st.rate;t.range=st.range*CELL;t.splashR=st.splashR*CELL;break;}if(t.lv>=maxLv(t.type))break;const cost=effCost(upCost(t.type,t.lv));if(S.gold<cost)break;S.gold-=cost;t.lv++;if(t.type==='wall'){const ws=WALL_STATS[t.lv-1];t.maxHp=ws.maxHp;t.hp=Math.min(ws.maxHp,t.hp+(ws.maxHp-WALL_STATS[t.lv-2].maxHp));}if(t.type==='summoner'){t.sf=0;t.sf2=undefined;}break;}case 'research':{const r=RESEARCH[inp.key];if(!r)break;const lv=S.research[inp.key]||0;if(lv>=r.maxLv)break;S.researchQueue=S.researchQueue||[];if(S.researchQueue.some(q=>q.key===inp.key))break;const cost=r.costs[lv];if(S.gold<cost)break;S.gold-=cost;S.researchQueue.push({key:inp.key,readyWave:S.wave+3,toLv:lv+1});break;}case 'targeting':{const t=S.towers.find(x=>x.c===inp.c&&x.r===inp.r);if(t)t.targeting=inp.mode;break;}}}
function _triggerOpNextWave(){if(!_opS||_opS.over||_opS.waveActive)return;const svS=S,svC=CLIFF_SET,svT=TREE_DECO,svR=_rng;S=_opS;CLIFF_SET=_opCliff;TREE_DECO=_opTree;_rng=_opRng;_tickingOp=true;triggerNextWave();_tickingOp=false;_opS=S;_opCliff=CLIFF_SET;_opTree=TREE_DECO;_opRng=_rng;S=svS;CLIFF_SET=svC;TREE_DECO=svT;_rng=svR;}
