function loadSFX(){for(const k in SFX_FILES){const f=SFX_FILES[k];SFX_POOL[k]=[];for(let i=0;i<SFX_POOL_SIZE;i++){const a=new Audio();a.preload='auto';a.src=f;a.addEventListener('error',()=>{console.warn('SFX load fail:',f,a.error&&a.error.code);},{once:true});SFX_POOL[k].push(a);}}console.log('SFX queued:',Object.keys(SFX_FILES).length*SFX_POOL_SIZE);return Promise.resolve();}
function ensureAudio(){for(const k in SFX_POOL){const a=SFX_POOL[k][0];if(!a)continue;a.volume=0;const p=a.play();if(p&&p.then)p.then(()=>{a.pause();a.currentTime=0;audioUnlocked=true;console.log('audio unlocked');}).catch(e=>{console.warn('audio unlock failed:',e.message);});break;}}
function sfx(cat,vol){if(muted||_tickingOp)return;const arr=SFX_POOL[cat];if(!arr||!arr.length)return;const i=(sfxIdx[cat]||0)%arr.length;sfxIdx[cat]=i+1;const a=arr[i];try{a.currentTime=0;a.volume=Math.min(1,(vol||0.5)*sfxVol);const p=a.play();if(p&&p.catch)p.catch(e=>{console.warn('sfx play fail:',cat,e.message);});}catch(e){console.warn('sfx error:',cat,e);}}
let _boostCtx=null;
function sfxBoost(cat,gain){if(muted)return;const arr=SFX_POOL[cat];if(!arr||!arr.length)return;const i=(sfxIdx[cat]||0)%arr.length;sfxIdx[cat]=i+1;const a=arr[i];try{if(!_boostCtx)_boostCtx=new(window.AudioContext||window.webkitAudioContext)();if(_boostCtx.state==='suspended')_boostCtx.resume();if(!a._boostSrc){const src=_boostCtx.createMediaElementSource(a);const gn=_boostCtx.createGain();gn.gain.value=gain||3;src.connect(gn);gn.connect(_boostCtx.destination);a._boostSrc=true;a._boostGn=gn;}else{a._boostGn.gain.value=gain||3;}a.currentTime=0;a.volume=1.0;const p=a.play();if(p&&p.catch)p.catch(e=>{console.warn('sfxBoost fail:',cat,e.message);});}catch(e){console.warn('sfxBoost error:',cat,e);}}
