function enemySprite(e){const flying=e.boss||e.kind==='armored'||e.kind==='ghost';const interval=e.kind==='ghost'?500:e.kind==='worm'?260:e.kind==='spider'?160:e.kind==='snail'?600:flying?110:340;const frame=Math.floor((Date.now()+(e.id||0)*1000)/interval)%2;let key;if(e.boss)key='eBoss';else if(e.kind==='elite')key='eElite';else if(e.kind==='armored')key='eArmored';else if(e.kind==='ghost')key='eGhost';else if(e.kind==='worm')key='eWorm';else if(e.kind==='spider')key='eSpider';else if(e.kind==='snail')key='eSnail';else if(e.kind==='swarm')key='eSwarm';else key='eNormal';return frame===1&&IMG[key+'2']?IMG[key+'2']:IMG[key];}
function pathTileFor(c,r){const idx=PATH_INDEX.get(c+','+r);if(idx===undefined)return IMG.pathE;const prev=idx>0?PATH_CELLS[idx-1]:null,next=idx<PATH_CELLS.length-1?PATH_CELLS[idx+1]:null;let N=false,S=false,E=false,W=false;for(const nb of [prev,next]){if(!nb)continue;const dc=nb[0]-c,dr=nb[1]-r;if(dc===1)E=true;if(dc===-1)W=true;if(dr===1)S=true;if(dr===-1)N=true;}if(N&&S)return IMG.pathN;if(E&&W)return IMG.pathE;if(N&&W)return IMG.pathNW;if(N&&E)return IMG.pathNE;if(S&&W)return IMG.pathSW;if(S&&E)return IMG.pathSE;if(E||W)return IMG.pathE;if(N||S)return IMG.pathN;return IMG.pathE;}
