function generatePath(){const MARGIN=2;const startR=MARGIN+Math.floor(rng()*(ROWS-MARGIN*2));const visited=new Set();const path=[[COLS-1,startR]];visited.add(`${COLS-1},${startR}`);let c=COLS-1,r=startR;while(c>0){const dirs=[];if(c-1>=0&&!visited.has(`${c-1},${r}`))dirs.push([c-1,r]);if(r-1>=MARGIN&&!visited.has(`${c},${r-1}`))dirs.push([c,r-1]);if(r+1<ROWS-MARGIN&&!visited.has(`${c},${r+1}`))dirs.push([c,r+1]);if(dirs.length===0)break;const weights=dirs.map(([nc])=>nc<c?3:1);const total=weights.reduce((a,b)=>a+b,0);let rand=rng()*total;let chosen=dirs[dirs.length-1];for(let i=0;i<dirs.length;i++){rand-=weights[i];if(rand<=0){chosen=dirs[i];break;}}const vertCount=path.filter(([pc])=>pc===c).length;if(vertCount>=3){const lo=dirs.find(([nc])=>nc<c);if(lo)chosen=lo;}c=chosen[0];r=chosen[1];path.push([c,r]);visited.add(`${c},${r}`);}if(path[path.length-1][0]!==0){const lC=path[path.length-1][0],lR=path[path.length-1][1];for(let cc=lC-1;cc>=0;cc--){if(!visited.has(`${cc},${lR}`)){path.push([cc,lR]);visited.add(`${cc},${lR}`);}else break;}}return path;}
function isGoodPath(p){if(p.length<20||p[p.length-1][0]!==0)return false;let t=0;for(let i=1;i<p.length-1;i++){const dc=p[i][0]-p[i-1][0],dc2=p[i+1][0]-p[i][0],dr=p[i][1]-p[i-1][1],dr2=p[i+1][1]-p[i][1];if(dc!==dc2||dr!==dr2)t++;}return t>=4;}
function makePath(){let p,t=0;do{p=generatePath();t++;}while(!isGoodPath(p)&&t<50);return p;}
function makeCliffs(ps,sc,sr,ec,er){const cl=new Set();const fb=new Set(ps);[[sc,sr],[ec,er]].forEach(([bc,br])=>{for(let dr=-1;dr<=1;dr++)for(let dc=-1;dc<=1;dc++)fb.add(`${bc+dc},${br+dr}`);});const cands=[];for(let r=0;r<ROWS;r++)for(let c=0;c<COLS;c++){if(!fb.has(`${c},${r}`))cands.push([c,r]);}for(let i=cands.length-1;i>0;i--){const j=Math.floor(rng()*(i+1));[cands[i],cands[j]]=[cands[j],cands[i]];}for(let i=0;i<Math.min(10,cands.length);i++)cl.add(`${cands[i][0]},${cands[i][1]}`);return cl;}

let PATH_CELLS,PATH_SET,PATH_PTS,GOLEM_PATH,CLIFF_SET,PATH_INDEX;
let TREE_DECO=[];
const TREE_PAIRS=[['tree0','tree4']];
function buildMapData(cells,opts){PATH_CELLS=cells;PATH_SET=new Set(cells.map(([c,r])=>c+','+r));PATH_INDEX=new Map();cells.forEach((cell,i)=>PATH_INDEX.set(cell[0]+','+cell[1],i));PATH_PTS=cells.map(([c,r])=>({x:c*CELL+CELL/2,y:r*CELL+CELL/2}));GOLEM_PATH=PATH_PTS.slice().reverse();const s=cells[0],e=cells[cells.length-1];if(opts&&opts.cliffs){CLIFF_SET=new Set(opts.cliffs);}else{CLIFF_SET=makeCliffs(PATH_SET,s[0],s[1],e[0],e[1]);}
  if(opts&&opts.tree){TREE_DECO=opts.tree;}else{TREE_DECO=[];for(let r=0;r<ROWS;r++){for(let c=0;c<COLS;c++){const key=`${c},${r}`;if(PATH_SET.has(key)||CLIFF_SET.has(key))continue;if(rng()<0.15){const p=Math.floor(rng()*2);TREE_DECO.push({c,r,p});}}}}}
function isOnCliff(t){return CLIFF_SET&&CLIFF_SET.has(`${t.c},${t.r}`);}
function radarBuffAt(c,r){let mx=0;for(const tt of S.towers){if(tt.type!=='radar')continue;const dc=c-tt.c,dr=r-tt.r;if(dc*dc+dr*dr<=RADAR_RANGE*RADAR_RANGE){const st=STATS.radar[tt.lv-1];if(st.buff>mx)mx=st.buff;}}return mx;}
function towerRange(t){const st=tStats(t.type,t.lv);if(!st)return 0;let base=st.range*CELL;if(CLIFF_RANGE_TYPES.has(t.type)&&isOnCliff(t))base*=2;if(t.type!=='radar'&&t.type!=='sword'){const buff=radarBuffAt(t.c,t.r);base*=(1+buff);}return base;}

