function tStats(type,lv){return STATS[type]?STATS[type][lv-1]:null;}
function upCost(type,lv){if(type==='wall')return WALL_UP_COST[lv-1]||null;return(UP_COST[type]||[])[lv-1]||null;}
function tCount(type){return S.towers.filter(t=>t.type===type).length;}
function mkGolemFromSummoner(lv){const s=STATS.summoner[lv-1];const aMul=researchMul('armor'),eMul=researchMul('engine');const hp=Math.round(s.golemHp*aMul);return{id:rng(),kind:'tank',pi:0,x:GOLEM_PATH[0].x,y:GOLEM_PATH[0].y,hp,mhp:hp,dmg:s.golemDmg,throwDmg:s.golemThrow,range:s.golemRange*CELL,throwRate:s.golemRate,throwCd:0,spd:s.golemSpd*eMul,lv,anim:1.0,throwAnim:0};}
function mkPlaneFromSummoner(lv){const s=STATS.summoner[lv-1];const aMul=researchMul('armor'),eMul=researchMul('engine');const hp=Math.round(s.golemHp*0.5*aMul);return{id:rng(),kind:'plane',pi:0,x:GOLEM_PATH[0].x,y:GOLEM_PATH[0].y,hp,mhp:hp,dmg:s.golemDmg,throwDmg:Math.round(s.golemThrow*1.2),range:s.golemRange*CELL*1.1,throwRate:s.golemRate*1.2,throwCd:0,spd:s.golemSpd*1.6*eMul,lv,anim:1.0,throwAnim:0};}
function updateBadges(){const sc=tCount('summoner'),sb=document.getElementById('summoner-badge'),sbtn=document.getElementById('summoner-btn');sb.textContent=`${sc}/${SUMMONER_LIMIT}`;if(sc>=SUMMONER_LIMIT){sb.style.background='#F7C1C1';sb.style.color='#A32D2D';sbtn.classList.add('disabled-btn');}else{sb.style.background='#E6F1FB';sb.style.color='#185FA5';sbtn.classList.remove('disabled-btn');}const wc=tCount('sword'),wb2=document.getElementById('sword-badge'),wbtn=document.getElementById('sword-btn');wb2.textContent=`${wc}/${SWORD_LIMIT}`;if(wc>=SWORD_LIMIT){wb2.style.background='#F7C1C1';wb2.style.color='#A32D2D';wbtn.classList.add('disabled-btn');}else{wb2.style.background='#FAEEDA';wb2.style.color='#854F0B';wbtn.classList.remove('disabled-btn');}const rc=tCount('radar'),rb=document.getElementById('radar-badge'),rbtn=document.getElementById('radar-btn');rb.textContent=`${rc}/${RADAR_LIMIT}`;if(rc>=RADAR_LIMIT){rb.style.background='#F7C1C1';rb.style.color='#A32D2D';rbtn.classList.add('disabled-btn');}else{rb.style.background='#D7F3E6';rb.style.color='#1D7A55';rbtn.classList.remove('disabled-btn');}}
function hasTree(c,r){return TREE_DECO.some(t=>t.c===c&&t.r===r);}
function canPlace(type,c,r){const key=`${c},${r}`;if(PATH_SET.has(key))return false;if(S.towers.some(t=>t.c===c&&t.r===r))return false;if(S.walls.some(w=>w.c===c&&w.r===r))return false;if(type==='lumber')return hasTree(c,r);if(hasTree(c,r))return false;if(CLIFF_SET.has(key))return type!=='wall'&&type!=='sword';return true;}

