function researchMul(key){return 1+(S.research?.[key]||0)*RESEARCH[key].perLv;}
function init(sandbox=false,diff='easy',mapData){if(mapData){buildMapData(mapData.cells,{cliffs:mapData.cliffs,tree:mapData.tree});}else{buildMapData(makePath());}const startGold=sandbox?9999999:MP_PENALTY==='gold_half'?Math.floor(DIFFICULTY[diff].gold*0.5):DIFFICULTY[diff].gold;S={hp:sandbox?9999:500,maxHp:sandbox?9999:500,gold:startGold,wave:0,kills:0,towers:[],walls:[],enemies:[],orbBullets:[],bullets:[],golems:[],golemBullets:[],explosions:[],slashFX:[],userTanks:[],waveActive:false,spawnDone:false,sq:[],st:0,placing:'arrow',sel:null,over:false,anim:null,hc:null,screenShake:0,bossDefeated:false,research:{armor:0,engine:0,powder:0,rate:0},researchQueue:[],sandbox,diff};wbBtn.disabled=false;wbBtn.style.display='';document.getElementById('wave-fill').style.width='0%';document.body.classList.toggle('sandbox-mode',!!sandbox);updateBadges();updateResearchUI();updateSandboxUI();}
function updateSandboxUI(){const sc=document.getElementById('sandbox-controls');if(!sc)return;sc.classList.toggle('show',!!S.sandbox);if(S.sandbox)document.getElementById('sb-wave').textContent='W'+(S.wave+1);}
