function updateDexUI(){const root=document.getElementById('dex-content');if(!root)return;const w=Math.max(1,(S?.wave||0));const d=diffMul();root.innerHTML=MONSTER_INFO.map(m=>{const isBoss=m.key==='boss';const em=isBoss?{hp:1,spd:1,tier:'normal'}:eliteMul(w,m.key);const isMythic=em.tier==='mythic';const isElite=em.tier==='elite';const hp=isBoss?(d.bossHp).toLocaleString():(Math.round(m.baseHp*hpScale(w)*d.hp*em.hp)).toLocaleString();const spd=isBoss?22:Math.round(m.baseSpd*spdScale(w)*d.spd*em.spd);const sprKey=m.sprite;const src=SPRITES[sprKey]||'';const tag=isMythic?'<span style="background:rgba(255,40,40,0.3);color:#FF4040;padding:1px 5px;border-radius:4px;font-size:9px;font-weight:700;border:0.5px solid rgba(255,80,80,0.6);margin-left:4px;text-shadow:0 0 3px rgba(255,0,0,0.5);">신화</span>':isElite?'<span style="background:rgba(160,80,220,0.3);color:#C28BFF;padding:1px 5px;border-radius:4px;font-size:9px;font-weight:700;border:0.5px solid rgba(194,139,255,0.5);margin-left:4px;">엘리트</span>':'';const cardStyle=isMythic?' style="border-color:rgba(255,80,80,0.6);box-shadow:0 0 8px rgba(255,40,40,0.3);"':isElite?' style="border-color:rgba(194,139,255,0.5);box-shadow:0 0 6px rgba(160,80,220,0.2);"':'';return `<div class="dex-card"${cardStyle}><div class="dx-img"><img src="${src}" alt=""/></div><div class="dx-info"><div class="dx-name"><span>${m.name}${tag}</span><span class="dx-flags">${m.flags}</span></div><div class="dx-stats"><span class="v">❤ ${hp}</span> · <span class="v">🐾 ${spd}</span></div><div class="dx-desc">${m.desc}</div></div></div>`;}).join('');}
const RESEARCH_META={armor:{label:'장갑개발',img:'assets/Top-down Tanks/PNG/Default size/tankBody_huge.png',traits:['탱크 체력 +20%/Lv','비행기 체력 +20%/Lv']},engine:{label:'엔진개량',img:'assets/Top-down Tanks/PNG/Default size/tank_darkLarge.png',traits:['탱크 속도 +15%/Lv','비행기 속도 +15%/Lv']},powder:{label:'화약정제',img:'assets/Top-down Tanks/PNG/Default size/bulletRed3.png',traits:['전체 공격력 +15%/Lv']},rate:{label:'발사가속',img:'assets/Top-down Tanks/PNG/Default size/barrelBlack_top.png',traits:['전체 공격속도 +12%/Lv']}};
let _selResearch=null;
function selectResearch(key){if(_selResearch===key){doResearch(key);return;}_selResearch=key;document.querySelectorAll('.ru-btn').forEach(b=>b.classList.toggle('sel',b.dataset.research===key));showTowerInfo(key);}
function _clearResearchSel(){_selResearch=null;document.querySelectorAll('.ru-btn').forEach(b=>b.classList.remove('sel'));}
function updateResearchUI(){for(const key of Object.keys(RESEARCH)){const r=RESEARCH[key];const lv=S.research?.[key]||0;const pending=(S.researchQueue||[]).find(q=>q.key===key);const lvEl=document.getElementById(`r-${key}-lvtxt`);if(lvEl)lvEl.textContent=`${lv}/${r.maxLv}`;const costEl=document.getElementById(`r-${key}-cost`);if(costEl)costEl.textContent=pending?`진행 중`:lv>=r.maxLv?'MAX':`${r.costs[lv]}G`;const btn=document.getElementById(`r-${key}-btn`);if(btn)btn.disabled=false;}}
function doResearch(key){if(isCoopGuest()){sendCoopCmd({kind:'research',key});setMsg('호스트에게 연구 명령 전송');return;}const r=RESEARCH[key];const lv=S.research[key]||0;if(lv>=r.maxLv)return;S.researchQueue=S.researchQueue||[];if(S.researchQueue.some(q=>q.key===key)){notifyMsg('이미 연구 진행 중');return;}const cost=r.costs[lv];if(S.gold<cost){notifyMsg('골드 부족');return;}S.gold-=cost;S.researchQueue.push({key,readyWave:S.wave+3,toLv:lv+1});lsInput({type:'research',key});sfx('upgrade',0.7);setMsg(`연구 시작 — 3웨이브 후 완료 (Lv${lv+1})`);_clearResearchSel();updateUI();updateResearchUI();}

function dst(a,b){return Math.hypot(a.x-b.x,a.y-b.y);}
function applyDmg(t,raw){const r=MP_PENALTY==='dmg_half'?Math.max(1,Math.floor(raw*0.5)):raw;if(t.boss){const ph=getBossPhase(t);const a=Math.max(1,Math.round(r*ph.defMult));t.hp-=a;return a;}t.hp-=r;return r;}
function getWallAt(c,r){return S.walls.find(w=>w.c===c&&w.r===r&&!(w.buildT>0));}
function enemyAttackDmg(e){const m=diffMul().dmg;let b;if(e.boss)b=500;else if(e.kind==='armored')b=60;else if(e.kind==='ghost')b=50;else if(e.kind==='snail')b=35;else if(e.kind==='elite')b=40;else if(e.kind==='spider')b=18;else if(e.kind==='worm')b=12;else if(e.kind==='swarm')b=10;else b=25;return Math.round(b*m);}

function getWT(w){const T={1:{cnt:9,elite:0,armor:0,swarm:0,gap:1.0,spdMult:1.0,hpMult:1.0},2:{cnt:12,elite:0,armor:0,swarm:0,gap:0.9,spdMult:1.0,hpMult:1.1},3:{cnt:15,elite:1,armor:0,swarm:0,gap:0.85,spdMult:1.05,hpMult:1.2},4:{cnt:18,elite:1,armor:0,swarm:0,gap:0.8,spdMult:1.05,hpMult:1.3},5:{cnt:20,elite:2,armor:1,swarm:0,gap:0.75,spdMult:1.1,hpMult:1.4},6:{cnt:22,elite:2,armor:1,swarm:0,gap:0.7,spdMult:1.1,hpMult:1.5},7:{cnt:25,elite:3,armor:1,swarm:5,gap:0.65,spdMult:1.15,hpMult:1.6},8:{cnt:28,elite:3,armor:2,swarm:8,gap:0.6,spdMult:1.15,hpMult:1.8},9:{cnt:30,elite:4,armor:2,swarm:8,gap:0.55,spdMult:1.2,hpMult:2.0},10:{cnt:35,elite:6,armor:4,swarm:10,gap:0.45,spdMult:1.35,hpMult:2.5},11:{cnt:38,elite:7,armor:5,swarm:12,gap:0.4,spdMult:1.4,hpMult:2.8},12:{cnt:42,elite:8,armor:6,swarm:14,gap:0.35,spdMult:1.5,hpMult:3.2},13:{cnt:46,elite:10,armor:7,swarm:16,gap:0.3,spdMult:1.6,hpMult:3.8},14:{cnt:50,elite:12,armor:8,swarm:18,gap:0.28,spdMult:1.7,hpMult:4.5},15:{cnt:54,elite:14,armor:9,swarm:20,gap:0.25,spdMult:1.8,hpMult:5.0},16:{cnt:58,elite:16,armor:10,swarm:22,gap:0.22,spdMult:1.9,hpMult:5.6},17:{cnt:62,elite:18,armor:12,swarm:24,gap:0.2,spdMult:2.0,hpMult:6.2},18:{cnt:66,elite:20,armor:14,swarm:26,gap:0.18,spdMult:2.1,hpMult:7.0},19:{cnt:70,elite:22,armor:16,swarm:28,gap:0.16,spdMult:2.2,hpMult:8.0},20:{cnt:74,elite:24,armor:18,swarm:30,gap:0.15,spdMult:2.3,hpMult:8.8},21:{cnt:78,elite:26,armor:19,swarm:32,gap:0.14,spdMult:2.4,hpMult:9.6},22:{cnt:82,elite:28,armor:20,swarm:34,gap:0.13,spdMult:2.5,hpMult:10.5},23:{cnt:86,elite:30,armor:21,swarm:35,gap:0.12,spdMult:2.6,hpMult:11.5},24:{cnt:90,elite:32,armor:22,swarm:36,gap:0.12,spdMult:2.7,hpMult:12.5},25:{cnt:94,elite:34,armor:23,swarm:37,gap:0.11,spdMult:2.8,hpMult:13.5},26:{cnt:98,elite:36,armor:24,swarm:38,gap:0.11,spdMult:2.9,hpMult:14.8},27:{cnt:102,elite:38,armor:25,swarm:39,gap:0.10,spdMult:3.0,hpMult:16.2},28:{cnt:106,elite:40,armor:26,swarm:40,gap:0.10,spdMult:3.1,hpMult:17.6},29:{cnt:110,elite:42,armor:28,swarm:42,gap:0.10,spdMult:3.2,hpMult:19.0},30:'boss'};if(S.mp){if(w>=30)return T[29];return T[w]||T[29];}return T[w]||T[29];}
function mkE(hp,spd,rw,color,kind,ex={}){const d=diffMul();const fhp=Math.round(hp*d.hp),fspd=spd*d.spd*(MP_PENALTY==='spd_double'?2:1);return{id:rng(),pi:0,x:PATH_PTS[0].x,y:PATH_PTS[0].y,hp:fhp,mhp:fhp,spd:fspd,rw,slow:0,st:0,hf:0,color,kind,boss:false,attackCd:0,...ex};}
const hpScale=w=>1+w*0.10,spdScale=w=>1+w*0.025,rwScale=w=>Math.round(w*0.25);
const MONSTER_INTRO={normal:1,swarm:2,elite:3,armored:5,snail:5,worm:10,ghost:15,spider:20};
function getMonsterTier(w,kind){const intro=MONSTER_INTRO[kind]||1;if(S?.diff==='challenge'&&w>=intro+10)return'mythic';if((S?.diff==='normal'||S?.diff==='challenge')&&w>=intro+5)return'elite';return'normal';}
function isHardElite(w,kind){return getMonsterTier(w,kind)!=='normal';}
function eliteMul(w,kind){const tier=getMonsterTier(w,kind);const fastSpd=kind==='swarm';if(tier==='mythic')return{hp:4.0,spd:fastSpd?1.7:1.0,rw:4.0,tier};if(tier==='elite')return{hp:3.0,spd:fastSpd?1.5:0.75,rw:3.0,tier};return{hp:1,spd:1,rw:1,tier:'normal'};}
function mkNormal(w,tpl){const m=eliteMul(w,'normal');const e=mkE(Math.round(165*hpScale(w)*m.hp),50*spdScale(w)*m.spd,Math.round((9+rwScale(w))*m.rw),'#BA7517','normal');if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;return e;}
function mkElite(w,tpl){const m=eliteMul(w,'elite');const e=mkE(Math.round(380*hpScale(w)*m.hp),40*spdScale(w)*m.spd,Math.round((22+rwScale(w))*m.rw),'#534AB7','elite');if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;return e;}
function mkArmored(w,tpl){const m=eliteMul(w,'armored');const e=mkE(Math.round(350*hpScale(w)*m.hp),30*spdScale(w)*m.spd,Math.round((36+rwScale(w)*2)*m.rw),'#444441','armored');if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;return e;}
function mkSwarm(w,tpl){const m=eliteMul(w,'swarm');const e=mkE(Math.round(32*hpScale(w)*m.hp),80*spdScale(w)*m.spd,Math.round((4+rwScale(w))*m.rw),'#EF9F27','swarm');if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;return e;}
function mkGhost(w,tpl){const m=eliteMul(w,'ghost');const e=mkE(Math.round(800*hpScale(w)*m.hp),40*spdScale(w)*m.spd,Math.round((70+rwScale(w)*2)*m.rw),'#C5B5E0','ghost');if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;return e;}
function mkWorm(w,tpl){const m=eliteMul(w,'worm');const e=mkE(Math.round(275*hpScale(w)*m.hp),40*spdScale(w)*m.spd,Math.round((32+rwScale(w))*m.rw),'#A05A2C','worm',{burrowed:false,burrowTimer:0,surfDur:2.5+rng()*1.0,burrowDur:1.4+rng()*0.6});if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;return e;}
function mkSpider(w,boss){const m=eliteMul(w,'spider');const e=mkE(Math.round(1400*hpScale(w)*m.hp),45*spdScale(w)*m.spd,Math.round((28+rwScale(w))*m.rw),'#8B4789','spider');if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;if(boss){e.x=boss.x;e.y=boss.y;e.pi=boss.pi;}return e;}
function mkSnail(w,tpl){const m=eliteMul(w,'snail');const e=mkE(Math.round(130*hpScale(w)*m.hp),22*spdScale(w)*m.spd,Math.round((22+rwScale(w))*m.rw),'#E89AC0','snail',{explResist:1.0,slowImmune:true});if(m.tier==='mythic')e.mythic=true;else if(m.tier==='elite')e.hardElite=true;return e;}
function mkBoss(){const hp=diffMul().bossHp;return{id:rng(),pi:0,x:PATH_PTS[0].x,y:PATH_PTS[0].y,hp,mhp:hp,spd:22*(MP_PENALTY==='spd_double'?2:1),rw:500,slow:0,st:0,hf:0,kind:'boss',boss:true,phase:0,phaseTransition:0,roarTimer:0,particles:[],slowImmune:true,attackCd:0};}
function pickWaveTypes(w){const pool=['normal'];if(w>=2)pool.push('swarm');if(w>=3)pool.push('elite');if(w>=5)pool.push('armor');if(w>=5)pool.push('snail');if(w>=10)pool.push('worm');if(w>=15)pool.push('ghost');if(w>=20)pool.push('spider');const must=new Set(['normal']);if(w===5)must.add('snail');if(w===10)must.add('worm');if(w===15)must.add('ghost');if(w===20)must.add('spider');const target=w<3?1:w<8?2:w<15?3:3;let s=(w*9301+49297)%233280;const rest=pool.filter(t=>!must.has(t));for(let i=rest.length-1;i>0;i--){s=(s*9301+49297)%233280;const j=Math.floor((s/233280)*(i+1));[rest[i],rest[j]]=[rest[j],rest[i]];}const chosen=new Set(must);for(const t of rest){if(chosen.size>=target)break;chosen.add(t);}if(!chosen.has('normal')&&!chosen.has('swarm')&&!chosen.has('elite')&&!chosen.has('armor'))chosen.add('normal');return chosen;}
function mkQueue(w){const q=[],tpl=getWT(w);if(tpl==='boss'){q.push({d:0,mk:mkBoss});for(let i=0;i<8;i++)q.push({d:4+i*1.2,mk:()=>mkElite(w,{hpMult:3.5,spdMult:1.4})});for(let i=0;i<4;i++)q.push({d:14+i*2.5,mk:()=>mkArmored(w,{hpMult:3,spdMult:1.2})});for(let i=0;i<6;i++)q.push({d:8+i*2,mk:()=>mkGhost(w,{hpMult:2.5,spdMult:1.3})});return q;}const types=pickWaveTypes(w);const gap=tpl.gap*1.7;let t=0;if(types.has('armor')){const armorCnt=Math.min(tpl.armor,4);for(let i=0;i<armorCnt;i++){q.push({d:t,mk:()=>mkArmored(w,tpl)});t+=gap*2.5;}}if(types.has('elite')){for(let i=0;i<tpl.elite;i++){q.push({d:t,mk:()=>mkElite(w,tpl)});t+=gap*1.5;}}if(types.has('ghost')){const ghostCount=2+(w-15);for(let i=0;i<ghostCount;i++){q.push({d:t,mk:()=>mkGhost(w,tpl)});t+=gap*1.8;}}if(types.has('worm')){const wormCount=Math.min(3+(w-10)*2,30);for(let i=0;i<wormCount;i++){q.push({d:t,mk:()=>mkWorm(w,tpl)});t+=gap*0.7;}}if(types.has('spider')){const spiderCount=Math.min(2+(w-20)*2,25);for(let i=0;i<spiderCount;i++){q.push({d:t,mk:()=>mkSpider(w)});t+=gap*0.6;}}if(types.has('snail')){const snailCount=Math.min(8+(w-5)*2,40);for(let i=0;i<snailCount;i++){q.push({d:t,mk:()=>mkSnail(w,tpl)});t+=gap*0.25;}}if(types.has('normal')){const norm=Math.max(1,tpl.cnt-tpl.armor-tpl.elite-tpl.swarm);for(let i=0;i<norm;i++){q.push({d:t,mk:()=>mkNormal(w,tpl)});t+=gap;}}if(types.has('swarm')){for(let i=0;i<tpl.swarm;i++){q.push({d:t,mk:()=>mkSwarm(w,tpl)});t+=gap*0.25;}}q.sort((a,b)=>a.d-b.d);return q;}

function boom(x,y,r,lv){sfx('boom',0.32);S.explosions.push({type:'sprite',x,y,r:r*0.6,life:1,rot:Math.random()*Math.PI*2},{type:'light',x,y,r:r*0.5,life:1,rot:Math.random()*Math.PI*2});}
function stoneCrash(x,y){sfx('glass',0.35);const ps=[];for(let i=0;i<8;i++){const a=Math.random()*Math.PI*2,s=30+Math.random()*50;ps.push({x,y,vx:Math.cos(a)*s,vy:Math.sin(a)*s,r:3+Math.random()*3,life:1,decay:1.2+Math.random()*0.5,color:['#B4B2A9','#888780','#D3D1C7','#5F5E5A'][Math.floor(Math.random()*4)]});}S.explosions.push({type:'pts',ps},{type:'ring',x,y,r:CELL*0.6,life:1,stone:true});}
function addSlashFX(cx,cy,angle,radius){S.slashFX.push({x:cx,y:cy,angle,radius,life:1.0,startAngle:angle-Math.PI*0.6,endAngle:angle+Math.PI*0.6});}
function bossRoar(x,y,big){S.explosions.push({type:'sprite',x,y,r:CELL*(big?2.2:1.5),life:1,rot:Math.random()*Math.PI*2},{type:'light',x,y,r:CELL*(big?1.8:1.2),life:1,rot:Math.random()*Math.PI*2});S.screenShake=big?0.8:0.4;}
function phaseFlash(x,y){S.explosions.push({type:'sprite',x,y,r:CELL*1.8,life:1,rot:Math.random()*Math.PI*2},{type:'light',x,y,r:CELL*1.5,life:1,rot:Math.random()*Math.PI*2});S.screenShake=1.2;}
function tickFX(dt){for(const e of S.explosions){if(e.type==='ring')e.life-=dt*(e.boss?1.5:e.stone?4:3);else if(e.type==='flash')e.life-=dt*8;else if(e.type==='sprite'){e.life-=dt*2.2;e.rot=(e.rot||0)+dt*1.5;}else if(e.type==='light'){e.life-=dt*3.5;e.rot=(e.rot||0)+dt*0.6;}else{for(const p of e.ps){p.x+=p.vx*dt;p.y+=p.vy*dt;p.vx*=0.85;p.vy*=0.85;p.life-=p.decay*dt;}e.life=Math.max(0,...e.ps.map(p=>p.life));}}S.explosions=S.explosions.filter(e=>e.life>0);for(const s of S.slashFX)s.life-=dt*12;S.slashFX=S.slashFX.filter(s=>s.life>0);}
function checkWaveComplete(){if(!S.waveActive||!S.spawnDone||S.enemies.length>0)return;if(_tickingOp){S.waveActive=false;S.gold+=effGold(waveBonus(S.wave));return;}if(!S.mp&&S.wave===MAX_WAVE){if(S.bossDefeated){victory();}return;}S.waveActive=false;const bonus=effGold(waveBonus(S.wave));S.gold+=bonus;coopMirrorGold(bonus);{const done=[];S.researchQueue=(S.researchQueue||[]).filter(q=>{if(S.wave>=q.readyWave){S.research[q.key]=q.toLv;done.push(q);return false;}return true;});if(done.length){updateResearchUI();notifyMsg(done.map(q=>`🔬 연구 완료 — ${q.key} Lv${q.toLv}`).join(' / '));sfx('upgrade',0.7);}}updateUI();const _willRoulette=!S.sandbox&&!S.mp&&S.wave%4===0;if(!S.mp){if(!_willRoulette)wbBtn.disabled=false;if(S.coop){S.coop.hostReady=null;S.coop.guestReady=null;S.coop.advancing=false;}}showWaveBanner(S.wave,bonus);sfx('wave_clear',1.0);if(ROULETTE_EFFECT){const _ri=ROULETTE_ITEMS.find(r=>r.id===ROULETTE_EFFECT);if(_ri&&S.wave-ROULETTE_EFFECT_WAVE>=_ri.dur){ROULETTE_EFFECT=null;updateEffectBadge();}}if(_willRoulette)setTimeout(()=>showWaveRoulette(),0);if(S.mp){wbBtn.style.display='none';window.FB.set(window.FB.ref(window.FB.db,`rooms/${S.mp.roomId}/${S.mp.role}/clearedWave`),S.wave);setMsg(`✓ Wave ${S.wave} 클리어 — 상대 대기 중...`);checkBothCleared();}}
function _enableSkipAfterDelay(){const sk=document.getElementById('sk');if(sk)sk.disabled=true;setTimeout(()=>{if(S&&S.waveActive&&sk)sk.disabled=false;},3000);}
function triggerNextWave(){if(S.waveActive||S.over)return;if(!_tickingOp)document.getElementById('roulette-screen').classList.remove('show');S.wave++;const newQ=mkQueue(S.wave);const remaining=(S.sq||[]).filter(s=>!s.done);if(remaining.length){newQ.forEach(s=>s.d+=S.st+0.3);S.sq=remaining.concat(newQ);}else{S.sq=newQ;S.st=0;}S.spawnDone=false;S.waveActive=true;S.bossDefeated=false;if(!_tickingOp){wbBtn.disabled=true;_enableSkipAfterDelay();}sfx('wave_start',0.7);showWaveBanner(S.wave);}
function checkBothCleared(){if(!S.mp||S.over||S.waveActive||S.mp.advancing)return;const my=S.mp.myCleared,op=S.mp.opCleared;if(my!=null&&op!=null&&my===op&&my===S.wave){S.mp.advancing=true;const delay=S.wave>0&&S.wave%4===0?8000:1500;setTimeout(()=>{if(!S.mp)return;S.mp.advancing=false;if(!S.over&&!S.waveActive)triggerNextWave();_triggerOpNextWave();},delay);}}
function _checkCoopWaveReady(){if(!S||!S.coop||S.coop.role!=='host'||S.waveActive||S.over||S.coop.advancing)return;if(S.coop.hostReady===S.wave&&S.coop.guestReady===S.wave){S.coop.hostReady=null;S.coop.guestReady=null;S.coop.advancing=true;const delay=S.wave>0&&S.wave%4===0?8000:1500;setTimeout(()=>{if(!S.coop)return;S.coop.advancing=false;if(!S.over&&!S.waveActive)triggerNextWave();},delay);}}

let last=null;
let SPEED_MUL=1;
const ROULETTE_ITEMS=[{id:'ice',label:'빙하기',desc:'공격속도 -20%',emoji:'🧊',color:'#FF5470',dur:8},{id:'poverty',label:'가난',desc:'획득 골드 -20%',emoji:'💸',color:'#FF5470',dur:8},{id:'noupgrade',label:'정체',desc:'타워 업그레이드 불가',emoji:'🚫',color:'#FF5470',dur:4},{id:'cheap',label:'발달',desc:'타워 비용 -40%',emoji:'📦',color:'#5DCEA5',dur:4},{id:'degen',label:'퇴화',desc:'적 이동속도 -30%',emoji:'🐢',color:'#5DCEA5',dur:8},{id:'recover',label:'복구',desc:'현재 부정 효과 제거',emoji:'✨',color:'#5DCEA5',dur:0},{id:'blank',label:'꽝',desc:'아무 효과 없음',emoji:'💨',color:'#888888',dur:0}];
let ROULETTE_EFFECT=null;
let ROULETTE_EFFECT_WAVE=0;
let MP_PENALTY=null;
function effGold(g){if(MP_PENALTY==='gold_half')g=Math.floor(g*0.5);return ROULETTE_EFFECT==='poverty'?Math.floor(g*0.8):g;}
function effRate(){return ROULETTE_EFFECT==='ice'?0.8:1.0;}
function effCost(c){return ROULETTE_EFFECT==='cheap'?Math.ceil(c*0.6):c;}
function effEnemySpd(s){return ROULETTE_EFFECT==='degen'?s*0.7:s;}
function updateEffectBadge(){const badge=document.getElementById('effect-badge');if(!badge)return;const tpEff=document.getElementById('tp-effect');if(!ROULETTE_EFFECT){badge.classList.remove('show');if(tpEff)tpEff.style.display='none';}else{const item=ROULETTE_ITEMS.find(r=>r.id===ROULETTE_EFFECT);if(!item){badge.classList.remove('show');if(tpEff)tpEff.style.display='none';}else{const remaining=item.dur-((S?S.wave:0)-ROULETTE_EFFECT_WAVE);badge.innerHTML=`<span>${item.emoji} ${item.label}</span><span class="eb-remaining">${remaining>0?remaining+'웨이브 남음':''}</span>`;badge.style.borderColor=item.color+'80';badge.classList.add('show');if(tpEff){tpEff.textContent=`${item.emoji} ${item.label}`;tpEff.style.display='';tpEff.style.color=item.color;}}}if(S&&S.mp&&window.FB&&S.mp.lastSyncedEffect!==ROULETTE_EFFECT){S.mp.lastSyncedEffect=ROULETTE_EFFECT;window.FB.set(window.FB.ref(window.FB.db,`rooms/${S.mp.roomId}/${S.mp.role}/effect`),ROULETTE_EFFECT||null).catch(()=>{});}}
const DIFFICULTY={easy:{hp:0.8,spd:1.0,gold:500,bossHp:40000,waveBonus:1.0,dmg:1.0},normal:{hp:1.05,spd:1.08,gold:500,bossHp:105000,waveBonus:1.0,dmg:1.15},challenge:{hp:1.4,spd:1.1,gold:500,bossHp:150000,waveBonus:1.0,dmg:1.2}};
