function showAlert(t,bg){const el=document.getElementById('wave-alert');el.textContent=t;el.style.background=bg;el.style.display='block';setTimeout(()=>el.style.display='none',3000);}
let _wbTimer=null;
function showWaveBanner(wave,bonus){
  if(_tickingOp)return;
  const el=document.getElementById('wave-banner');
  if(_wbTimer){clearTimeout(_wbTimer);_wbTimer=null;}
  el.classList.remove('show','hide');
  let color,bg,icon,title,sub,reward='';
  if(bonus!==undefined){
    color='#5dffb4';bg='rgba(8,32,20,0.90)';icon='✓';title=`웨이브 ${wave} 완료`;sub='';reward=`+${bonus}G`;
  } else if(wave===MAX_WAVE){
    color='#ff5470';bg='rgba(40,4,4,0.92)';icon='☠';title='FINAL WAVE';sub='최종 보스 출현!';
  } else if(wave>=20){
    color='#bf7fff';bg='rgba(22,4,44,0.92)';icon='💀';title=`WAVE ${wave}`;sub='지옥 웨이브';
  } else if(wave===15){
    color='#C5B5E0';bg='rgba(28,18,48,0.94)';icon='👻';title=`WAVE ${wave}`;sub='유령 출현!';
  } else if(wave===10){
    color='#D8A06B';bg='rgba(38,22,8,0.94)';icon='🪱';title=`WAVE ${wave}`;sub='지렁이 출현!';
  } else if(wave>=10){
    color='#ffd166';bg='rgba(38,22,4,0.92)';icon='⚠';title=`WAVE ${wave}`;sub='강화 웨이브';
  } else {
    color='#00d9ff';bg='rgba(4,18,38,0.88)';icon='';title=`WAVE ${wave}`;sub='';
  }
  el.style.background=bg;
  el.innerHTML=`<div><span class="wb-icon">${icon}</span><span class="wb-num" style="color:${color};text-shadow:0 0 14px ${color}">${title}</span></div>` +
    `${sub?`<div class="wb-sub" style="color:${color}cc">${sub}</div>`:''}` +
    `${reward?`<div class="wb-reward" style="color:#ffd166">${reward} 💰</div>`:''}`;
  el.style.display='block';
  void el.offsetWidth;
  el.classList.add('show');
  const hold=bonus!==undefined?2200:1800;
  _wbTimer=setTimeout(()=>{
    el.classList.remove('show');el.classList.add('hide');
    setTimeout(()=>{el.style.display='none';el.classList.remove('hide');},350);
    _wbTimer=null;
  },hold);
}
