tElementById('ip').classList.add('vis');const onCliff=isOnCliff(t)&&CLIFF_RANGE_TYPES.has(t.type);document.getElementById('it').textContent=b.label+' '+b.emoji+(onCliff?' 🪨':'');const le=document.getElementById('il');le.textContent='Lv'+t.lv;le.style.background=lc.bg;le.style.color=lc.tx;document.getElementById('ip-ammo-wrap').style.display='none';const tgWrap=document.getElementById('ip-target-wrap');const hasTargeting=['arrow','cannon','ice','sword','summoner','missile'].includes(t.type);tgWrap.style.display=hasTargeting?'block':'none';if(hasTargeting){const cur=t.targeting||'first';tgWrap.querySelectorAll('.tg-btn').forEach(b=>b.classList.toggle('sel',b.dataset.tg===cur));const TG_DESC={first:'가장 앞 — 베이스에 가장 가까운 적을 우선 공격',last:'가장 뒤 — 스폰 위치에 가장 가까운 적을 공격',weak:'약한 적 — 현재 체력이 가장 낮은 적을 공격',strong:'센 적 — 현재 체력이 가장 높은 적을 공격 (보스/탱커 처리에 유리)',random:'랜덤 — 사거리 안 적을 무작위로 선택'};document.getElementById('tg-desc').textContent=TG_DESC[cur]||'';}
