function selAny(obj){S.sel=obj;S.placing=null;S.selEnemy=null;document.getElementById('eip').classList.remove('vis');document.querySelectorAll('.tbtn').forEach(b=>b.classList.remove('sel'));refreshPanel();if(obj)requestAnimationFrame(()=>_posIp(obj));if(obj){if(obj.userTank){setMsg('🚙 탱크 선택 — 빈 칸 클릭으로 이동, 판매로 제거');return;}const cl=obj.type!=='wall'&&isOnCliff(obj)&&CLIFF_RANGE_TYPES.has(obj.type);setMsg(`${BASE[obj.type].label} 선택${cl?' — 절벽 사거리 ×2':''}`);}}

// ── 캔버스 이벤트 (공통 함수로 추출) ──
function _getCell(cx,cy){
  const r=canvas.getBoundingClientRect();
  const px=cx-r.left,py=cy-r.top;
  const wx=(px-camX)/camZoom,wy=(py-camY)/camZoom;
  const c=Math.floor(wx/CELL),rr=Math.floor(wy/CELL);
  return(c>=0&&c<COLS&&rr>=0&&rr<ROWS)?{c,r:rr}:null;
}
function handleCanvasClick(cx,cy){
  if(S.over)return;
  {const cr=canvas.getBoundingClientRect();const px=cx-cr.left,py=cy-cr.top;const wx=(px-camX)/camZoom,wy=(py-camY)/camZoom;const hit=S.enemies.find(e=>!e.burrowed&&Math.hypot(e.x-wx,e.y-wy)<eRad(e)*2.2);if(hit){showEnemyPanel(hit);return;}}
  if(S.selEnemy){S.selEnemy=null;document.getElementById('eip').classList.remove('vis');}
  const cell=_getCell(cx,cy);if(!cell)return;
  if(isCoopGuest()){const ex=S.towers.find(t=>t.c===cell.c&&t.r===cell.r)||S.walls.find(w=>w.c===cell.c&&w.r===cell.r);if(ex){S.placing=null;document.querySelectorAll('.tbtn').forEach(b=>b.classList.remove('sel'));S.sel=ex;refreshPanel();return;}if(S.placing){if(S.placing==='stone'){sendCoopCmd({kind:'stone',c:cell.c,r:cell.r});}else if(S.placing==='lumber'){sendCoopCmd({kind:'lumber',c:cell.c,r:cell.r});}else{sendCoopCmd({kind:'place',type:S.placing,c:cell.c,r:cell.r});}setMsg('호스트에게 명령 전송');return;}S.sel=null;document.getElementById('ip').classList.remove('vis');return;}
  processCellAction(cell.c,cell.r);
}
function processCellAction(c,rr){
  const eu=(S.userTanks||[]).find(t=>t.c===c&&t.r===rr);if(eu){selAny(eu);S.placing=null;document.querySelectorAll('.tbtn').forEach(b=>b.classList.remove('sel'));return;}
  const ewSel=S.walls.find(w=>w.c===c&&w.r===rr);if(ewSel&&!S.placing){selAny(ewSel);return;}
  const etSel=S.towers.find(t=>t.c===c&&t.r===rr);if(etSel&&!S.placing){selAny(etSel);return;}
  if(S.sel&&S.sel.userTank&&!S.placing){const key=`${c},${rr}`;if(PATH_SET.has(key)||CLIFF_SET.has(key)||hasTree(c,rr)){setMsg('이 칸으로는 못 감');return;}const path=findTankPath(S.sel.c,S.sel.r,c,rr);if(!path||path.length<2){setMsg('경로를 찾을 수 없음');return;}S.sel.path=path.slice(1);const next=S.sel.path[0];S.sel.targetX=next.c*CELL+CELL/2;S.sel.targetY=next.r*CELL+CELL/2;S.sel.targetC=next.c;S.sel.targetR=next.r;setMsg(`🚙 이동 중 (${S.sel.path.length}칸)...`);return;}
  if(S.placing==='usertank'){const key=`${c},${rr}`;if(PATH_SET.has(key)){setMsg('길 위에 못 놓음');return;}if(CLIFF_SET.has(key)){setMsg('돌 위에 못 놓음');return;}if(S.towers.some(x=>x.c===c&&x.r===rr)||S.walls.some(x=>x.c===c&&x.r===rr)){setMsg('이미 뭔가 있음');return;}if(hasTree(c,rr)){setMsg('나무 위에 못 놓음');return;}if(S.gold<350){notifyMsg('골드 부족 (350G)');return;}S.gold-=350;const st1=STATS.usertank[0];S.userTanks.push({id:rng(),userTank:true,type:'usertank',c,r:rr,x:c*CELL+CELL/2,y:rr*CELL+CELL/2,bodyFacing:0,turretFacing:0,spd:120,cd:0,lv:1,range:st1.range*CELL,dmg:st1.dmg,rate:st1.rate,splashR:st1.splashR*CELL,ammo:'explosive',kills:0});lsInput({type:'usertank',c,r:rr});updateUI();setMsg('🚙 탱크 배치됨 — 클릭해서 선택, 다시 클릭으로 이동');sfx('place',0.4);return;}
  const ew=S.walls.find(w=>w.c===c&&w.r===rr);if(ew){selAny(ew);return;}
  const et=S.towers.find(t=>t.c===c&&t.r===rr);if(et){selAny(et);return;}
  if(S.placing==='wall'){
    if(!PATH_SET.has(`${c},${rr}`)){setMsg('방어벽은 길 위에만 설치할 수 있어요.');return;}
    if(S.walls.some(w=>w.c===c&&w.r===rr)||S.towers.some(t=>t.c===c&&t.r===rr)){setMsg('이미 뭔가 있는 칸이에요.');return;}
    if(S.gold<20){notifyMsg('골드 부족 (20G)');return;}
    S.gold-=20;S.walls.push({id:rng(),c,r:rr,type:'wall',lv:1,hp:300,maxHp:300,hf:0,buildT:5,buildMax:5});lsInput({type:'wall',c,r:rr});updateUI();setMsg('방어벽 건설 시작 (5초)');sfx('place',0.4);return;
  }
  if(S.placing==='stone'){const key=`${c},${rr}`;if(PATH_SET.has(key)){setMsg('길 위에는 돌을 놓을 수 없어요');return;}if(S.towers.some(t=>t.c===c&&t.r===rr)||S.walls.some(w=>w.c===c&&w.r===rr)){setMsg('이미 뭔가 있는 칸이에요');return;}if(hasTree(c,rr)){setMsg('나무를 먼저 제거하세요');return;}if(S.gold<100){notifyMsg('골드 부족 (100G)');return;}S.gold-=100;if(CLIFF_SET.has(key)){CLIFF_SET.delete(key);lsInput({type:'stone',c,r:rr,remove:true});setMsg('돌 제거');}else{CLIFF_SET.add(key);lsInput({type:'stone',c,r:rr,remove:false});setMsg('돌 설치');}updateUI();sfx('place',0.4);return;}
  if(S.placing){
    if(!canPlace(S.placing,c,rr)){
      if(CLIFF_SET.has(`${c},${rr}`)&&S.placing==='sword')setMsg('🪨 절벽엔 근거리 포탑를 설치할 수 없어요!');
      else if(PATH_SET.has(`${c},${rr}`))setMsg('경로 위에는 타워를 지을 수 없어요.');
      else setMsg('여기엔 설치할 수 없어요.');return;
    }
    if(!S.sandbox){if(S.placing==='sword'&&tCount('sword')>=SWORD_LIMIT){notifyMsg(`근거리 포탑는 최대 ${SWORD_LIMIT}개까지 설치할 수 있어요.`);return;}
    if(S.placing==='summoner'&&tCount('summoner')>=SUMMONER_LIMIT){notifyMsg(`사령관은 최대 ${SUMMONER_LIMIT}개까지 설치할 수 있어요.`);return;}
    if(S.placing==='radar'&&tCount('radar')>=RADAR_LIMIT){notifyMsg(`레이더는 최대 ${RADAR_LIMIT}개까지 설치할 수 있어요.`);return;}}
    const b=BASE[S.placing];const placeCost=effCost(b.cost);if(S.gold<placeCost){notifyMsg(`골드 부족 (${placeCost}G)`);return;}
    if(S.placing==='lumber'){S.gold-=placeCost;TREE_DECO=TREE_DECO.filter(t=>!(t.c===c&&t.r===rr));lsInput({type:'lumber',c,r:rr});updateUI();setMsg('나무 제거됨');sfx('place',0.4);return;}
    S.gold-=placeCost;
    const nt={id:rng(),c,r:rr,x:c*CELL+CELL/2,y:rr*CELL+CELL/2,type:S.placing,lv:1,kills:0,cd:0,sf:0,sf2:undefined};
    S.towers.push(nt);lsInput({type:'place',towerType:S.placing,c,r:rr});updateUI();updateBadges();setMsg('');sfx('place',0.45);
  }else{
    S.sel=null;document.getElementById('ip').classList.remove('vis');setMsg('');
  }
}

// ── 몬스터 선택 패널 ──
const ENEMY_LABELS={normal:'일반',swarm:'군집',elite:'정예',armored:'기갑',snail:'달팽이',worm:'두더지',ghost:'유령',spider:'거미',boss:'보스'};
let _eipH=140;
function _posEip(e){
  const eip=document.getElementById('eip');
  const cwEl=document.getElementById('cw');
  const cwRect=cwEl.getBoundingClientRect();
  const cr=canvas.getBoundingClientRect();
  const sx=e.x*camZoom+camX+cr.left-cwRect.left;
  const sy=e.y*camZoom+camY+cr.top-cwRect.top;
  const pw=190,ph=_eipH;
  let lx=sx-pw/2;
  let ty=sy-ph-40;
  lx=Math.max(4,Math.min(cwRect.width-pw-4,lx));
  if(ty<4)ty=sy+18;
  if(ty+ph>cwRect.height-4)ty=cwRect.height-ph-4;
  eip.style.left=lx+'px';eip.style.top=ty+'px';
}
function _updateEipContent(e){
  const pct=Math.max(0,e.hp/e.mhp*100);
  document.getElementById('eip-hp-val').textContent=`${Math.ceil(Math.max(0,e.hp)).toLocaleString()}/${e.mhp.toLocaleString()}`;
  const fill=document.getElementById('eip-hp-fill');
  fill.style.width=pct+'%';
  fill.style.background=pct>50?'#5dffb4':pct>25?'#ffd166':'#ff5470';
  document.getElementById('eip-spd-val').textContent=Math.round(e.spd*(1-(e.slow||0)));
  const traits=[];
  if(e.kind==='ghost')traits.push('👻 유령(탐지필요)');
  if(e.kind==='worm')traits.push('🕳 잠복능력');
  if(e.burrowed)traits.push('🕳 잠복중');
  if(e.slowImmune)traits.push('❄ 슬로우면역');
  if(e.explResist)traits.push('💥 폭발저항');
  if(e.st>0&&!e.slowImmune)traits.push('❄ 감속중');
  if(e.boss&&e.phase!=null)traits.push(`💀 페이즈${e.phase+1}`);
  if(e.mythic)traits.push('✨ 신화');
  else if(e.hardElite)traits.push('⚡ 강화엘리트');
  document.getElementById('eip-traits').innerHTML=traits.map(t=>`<span class="eip-trait">${t}</span>`).join('');
}
function showEnemyPanel(e){
  S.selEnemy=e;
  S.sel=null;document.getElementById('ip').classList.remove('vis');
  const eip=document.getElementById('eip');
  const lbl=(e.mythic?'[신화] ':e.hardElite?'[엘리트] ':'')+( ENEMY_LABELS[e.kind]||e.kind)+(e.boss?' 보스':'');
  document.getElementById('eip-name').textContent=lbl;
  _updateEipContent(e);
  eip.classList.add('vis');
  requestAnimationFrame(()=>{_eipH=eip.offsetHeight||140;_posEip(e);});
}
document.getElementById('close-eip').addEventListener('click',()=>{if(S)S.selEnemy=null;document.getElementById('eip').classList.remove('vis');});
// ── 타워 선택 패널 위치 ──
function _posIp(t){
  if(!t)return;
  const ip=document.getElementById('ip');
  const cwEl=document.getElementById('cw');
  const cwRect=cwEl.getBoundingClientRect();
  const canvasRect=canvas.getBoundingClientRect();
  const sx=t.c*CELL*camZoom+camX+canvasRect.left-cwRect.left;
  const sy=t.r*CELL*camZoom+camY+canvasRect.top-cwRect.top;
  const pw=220,ph=ip.offsetHeight||200;
  const cellPx=CELL*camZoom;
  let lx=sx-pw-6;
  let ty=sy-ph-6;
  if(lx<4)lx=sx+cellPx+6;
  if(lx+pw>cwRect.width-4)lx=cwRect.width-pw-4;
  if(ty<4)ty=4;
  if(ty+ph>cwRect.height-4)ty=cwRect.height-ph-4;
  ip.style.left=lx+'px';
  ip.style.top=ty+'px';
}
// ── 카메라 이벤트 (마우스 + 터치) ──
function _pinchDist(t0,t1){const dx=t0.clientX-t1.clientX,dy=t0.clientY-t1.clientY;return Math.sqrt(dx*dx+dy*dy);}
function _canvasXY(cx,cy){const r=canvas.getBoundingClientRect();return{x:cx-r.left,y:cy-r.top};}
function _zoomAt(cx,cy,factor){const oldZ=camZoom;camZoom=Math.max(0.75,Math.min(4,camZoom*factor));camX=cx-(cx-camX)*(camZoom/oldZ);camY=cy-(cy-camY)*(camZoom/oldZ);clampCam();if(S&&S.sel)_posIp(S.sel);}

// 마우스
let _mDrag=null;
canvas.addEventListener('mousedown',e=>{if(e.button!==0)return;_mDrag={sx:e.clientX,sy:e.clientY,cx0:camX,cy0:camY,moved:false};if(S)S.hc=_getCell(e.clientX,e.clientY);canvas.style.cursor='grabbing';});
canvas.addEventListener('mousemove',e=>{
  if(_mDrag){const dx=e.clientX-_mDrag.sx,dy=e.clientY-_mDrag.sy;if(!_mDrag.moved&&dx*dx+dy*dy>25)_mDrag.moved=true;if(_mDrag.moved){camX=_mDrag.cx0+dx;camY=_mDrag.cy0+dy;clampCam();if(S)S.hc=null;if(S&&S.sel)_posIp(S.sel);return;}}
  if(S)S.hc=_getCell(e.clientX,e.clientY);
});
canvas.addEventListener('mouseup',e=>{if(e.button!==0)return;if(_mDrag&&!_mDrag.moved)handleCanvasClick(e.clientX,e.clientY);_mDrag=null;canvas.style.cursor='crosshair';});
canvas.addEventListener('mouseleave',()=>{if(S)S.hc=null;_mDrag=null;canvas.style.cursor='crosshair';});
canvas.addEventListener('dblclick',e=>{e.preventDefault();resetCam();});
canvas.addEventListener('wheel',e=>{e.preventDefault();const p=_canvasXY(e.clientX,e.clientY);_zoomAt(p.x,p.y,e.deltaY<0?1.1:1/1.1);},{passive:false});

// 터치
let _ts=null,_tp=null,_tLastTap=0,_tDragging=false;
canvas.addEventListener('touchstart',e=>{
  e.preventDefault();
  if(e.touches.length===1){const t=e.touches[0];_ts={sx:t.clientX,sy:t.clientY,cx0:camX,cy0:camY};_tp=null;_tDragging=false;if(S)S.hc=_getCell(t.clientX,t.clientY);}
  else if(e.touches.length===2){_tp={d:_pinchDist(e.touches[0],e.touches[1]),mx:_canvasXY((e.touches[0].clientX+e.touches[1].clientX)/2,(e.touches[0].clientY+e.touches[1].clientY)/2)};_ts=null;if(S)S.hc=null;}
},{passive:false});
canvas.addEventListener('touchmove',e=>{
  e.preventDefault();
  if(e.touches.length===2&&_tp){const nd=_pinchDist(e.touches[0],e.touches[1]);_zoomAt(_tp.mx.x,_tp.mx.y,nd/_tp.d);_tp.d=nd;return;}
  if(e.touches.length===1&&_ts){const t=e.touches[0],dx=t.clientX-_ts.sx,dy=t.clientY-_ts.sy;if(!_tDragging&&dx*dx+dy*dy>100)_tDragging=true;if(_tDragging){camX=_ts.cx0+dx;camY=_ts.cy0+dy;clampCam();if(S)S.hc=null;if(S&&S.sel)_posIp(S.sel);}else{if(S)S.hc=_getCell(t.clientX,t.clientY);}}
},{passive:false});
canvas.addEventListener('touchend',e=>{
  e.preventDefault();
  if(e.touches.length===0){const t=e.changedTouches[0];if(!_tDragging&&_ts){const now=Date.now();if(now-_tLastTap<300){resetCam();}else{handleCanvasClick(t.clientX,t.clientY);}_tLastTap=now;}if(S)S.hc=null;_ts=null;_tp=null;_tDragging=false;}
  else if(e.touches.length===1){_tp=null;const t=e.touches[0];_ts={sx:t.clientX,sy:t.clientY,cx0:camX,cy0:camY};_tDragging=false;}
},{passive:false});
canvas.addEventListener('touchcancel',()=>{if(S)S.hc=null;_ts=null;_tp=null;_tDragging=false;});

window.addEventListener('keydown',e=>{if((e.key==='e'||e.key==='E')&&!S.over&&S.sel){e.preventDefault();doUpgrade();}});

