{const tp=document.getElementById('tp');tp.addEventListener('wheel',e=>{e.preventDefault();tp.scrollLeft+=e.deltaY||e.deltaX;},{passive:false});let _tpDrag=false,_tpDragX=0,_tpDragSL=0;tp.addEventListener('mousedown',e=>{_tpDrag=true;_tpDragX=e.clientX;_tpDragSL=tp.scrollLeft;tp.style.cursor='grabbing';e.preventDefault();});document.addEventListener('mousemove',e=>{if(!_tpDrag)return;tp.scrollLeft=_tpDragSL+(_tpDragX-e.clientX);});document.addEventListener('mouseup',()=>{if(_tpDrag){_tpDrag=false;tp.style.cursor='';}});}
