const TBTN_INFO={arrow:{name:'고속 포탑',traits:['공중 공격']},cannon:{name:'광역 포탑',traits:['공중 공격','광역 폭발']},ice:{name:'냉동 포탑',traits:['유령 공격','공중 공격','적 둔화']},summoner:{name:'사령관',traits:['공중 공격','탱크 소환']},sword:{name:'근거리 포탑',traits:['유령 공격']},radar:{name:'레이더',traits:['유령 발각','사거리 버프']},missile:{name:'미사일',traits:['공중 공격','광역 폭발','최소사거리']},usertank:{name:'탱크',traits:['이동 가능','광역 폭발']},wall:{name:'방어벽',traits:['경로 차단','HP 있음','업그레이드']},lumber:{name:'벌목',traits:['나무 제거']},stone:{name:'절벽 돌',traits:['절벽 생성','사거리 2배']},armor:{name:'장갑개발',traits:['탱크 체력 +20%/Lv','비행기 체력 +20%/Lv']},engine:{name:'엔진개량',traits:['탱크 속도 +15%/Lv','비행기 속도 +15%/Lv']},powder:{name:'화약정제',traits:['전체 공격력 +15%/Lv']},rate:{name:'발사가속',traits:['전체 공격속도 +12%/Lv']}};
function showTowerInfo(type){const info=TBTN_INFO[type];if(!info){document.getElementById('ti-name').textContent='설명';document.getElementById('ti-traits').innerHTML='';return;}document.getElementById('ti-name').textContent=info.name;document.getElementById('ti-traits').innerHTML=info.traits.map(t=>`<span class="ti-trait">${t}</span>`).join('');}
