wbBtn.addEventListener('click',()=>{
  try{
  if(!S){notifyMsg('[오류] 게임이 초기화되지 않음');return;}
  if(isCoopGuest()){if(S.waveActive||S.over||S.coop.guestWaveReady)return;sendCoopCmd({kind:'wave',wave:S.wave});S.coop.guestWaveReady=true;wbBtn.disabled=true;setMsg('준비 완료 — 호스트 대기 중...');return;}
  if(S.waveActive||S.over||(!S.mp&&!S.coop&&S.wave>=MAX_WAVE))return;
  if(S.mp){window.FB.set(window.FB.ref(window.FB.db,`rooms/${S.mp.roomId}/${S.mp.role}/clearedWave`),S.wave);wbBtn.disabled=true;setMsg(`✓ 준비 — 상대 대기 중...`);return;}
  if(S.coop&&S.coop.role==='host'){S.coop.hostReady=S.wave;wbBtn.disabled=true;setMsg('준비 완료 — 게스트 대기 중...');_checkCoopWaveReady();return;}
  S.wave++;const newQ=mkQueue(S.wave);const remaining=(S.sq||[]).filter(s=>!s.done);if(remaining.length){newQ.forEach(s=>s.d+=S.st+0.3);S.sq=remaining.concat(newQ);}else{S.sq=newQ;S.st=0;}S.spawnDone=false;S.waveActive=true;S.bossDefeated=false;wbBtn.disabled=true;_enableSkipAfterDelay();sfx('wave_start',0.7);
  showWaveBanner(S.wave);
  if(!S.mp&&S.wave===MAX_WAVE){bossRoar(W/2,H/2,true);}
  }catch(e){console.error('wb click error:',e);notifyMsg('[웨이브오류] '+e.message);}
});

