function spinRW(){if(_rwSpinning)return;_rwSpinning=true;const _prevEffect=ROULETTE_EFFECT,_prevEffectWave=ROULETTE_EFFECT_WAVE;buildCSGOStrip();_rwChosenIdx=Math.floor(rng()*ROULETTE_ITEMS.length);const n=ROULETTE_ITEMS.length;let winIdx=Math.floor(CSGO_N*0.75);while(winIdx%n!==_rwChosenIdx)winIdx++;winIdx=Math.min(winIdx,CSGO_N-2);const outer=document.getElementById('csgo-track-outer');const cw=outer?outer.clientWidth:320;const finalX=-(winIdx*CSGO_TOTAL+5+CSGO_W/2-cw/2);const track=document.getElementById('csgo-track');const dur=3800+Math.random()*700;const t0=performance.now();function frame(now){const t=Math.min(1,(now-t0)/dur);const ease=1-Math.pow(1-t,4);track.style.transform=`translateX(${finalX*ease}px)`;if(t<1){requestAnimationFrame(frame);}else{_rwSpinning=false;ROULETTE_EFFECT=ROULETTE_ITEMS[_rwChosenIdx].id;ROULETTE_EFFECT_WAVE=S?S.wave:0;const item=ROULETTE_ITEMS[_rwChosenIdx];const _negatives=['ice','poverty','noupgrade'];if(ROULETTE_EFFECT==='blank'){ROULETTE_EFFECT=null;}else if(ROULETTE_EFFECT==='recover'){if(_negatives.includes(_prevEffect)){ROULETTE_EFFECT=null;}else{ROULETTE_EFFECT=_prevEffect;ROULETTE_EFFECT_WAVE=_prevEffectWave;}}updateEffectBadge();track.children[winIdx].classList.add('winner');document.getElementById('roulette-result').textContent=item.emoji+' '+item.label+' — '+item.desc;setTimeout(()=>{document.getElementById('roulette-screen').classList.remove('show');if(_rwContext==='wave'&&S&&!S.mp&&!S.waveActive)wbBtn.disabled=false;},3000);}}requestAnimationFrame(frame);}
